mapper.insert:
INSERT INTO ea_archive_group_execute_task (
    group_id, start_time, execute_status, processed_records, finished_flag
) VALUES (
    #{groupId}, #{startTime}, #{executeStatus}, #{processedRecords}, COALESCE(#{finishedFlag}, 0)
)

mapper.select:
SELECT 
FROM ea_archive_group_execute_task

    AND execute_status = #{status}
    AND deleted = 0

ORDER BY id DESC
LIMIT #{offset}, #{size}

SELECT t.id, t.group_id, t.start_time, t.end_time, t.execute_status, t.error_msg, t.processed_records, t.processed_speed, t.heartbeat_time, t.finished_flag, t.created_time, t.updated_time, t.creator_id, t.updater_id, t.deleted FROM ea_archive_group_execute_task t JOIN ea_archive_group g ON g.id = t.group_id AND g.deleted = 0
AND t.execute_status = #{status} AND t.deleted = 0 AND EXISTS ( SELECT 1 FROM ea_user_datasource_permission p WHERE p.deleted = 0 AND p.user_id = #{userId} AND p.datasource_id = g.source_datasource_id AND p.permission_type = 'READ' )
ORDER BY t.id DESC LIMIT #{offset}, #{size}

SELECT FROM ea_archive_group_execute_task WHERE deleted = 0 AND execute_status IN (0, 1, 4) AND id IN ( SELECT MAX(id) FROM ea_archive_group_execute_task WHERE deleted = 0 AND execute_status IN (0, 1, 4) AND group_id IN
#{groupId}
GROUP BY group_id )

SELECT COUNT(1)
FROM ea_archive_group_execute_task
WHERE deleted = 0
  AND group_id = #{groupId}
  AND execute_status = #{status}

SELECT 
FROM ea_archive_group_execute_task
WHERE deleted = 0
  AND group_id = #{groupId}
ORDER BY id DESC
LIMIT #{limit}
